func solve(nums []int64, k int64) int64 {
    totalSum := int64(0)
    for _, num := range nums {
        totalSum += num
    }

    prefixSum := int64(0)
    dpPrev := int64(0)
    minRemainder := make(map[int64]int64)
    minRemainder[0] = 0

    for _, num := range nums {
        prefixSum += num
        currentR := prefixSum % k

        var candidate int64
        if val, ok := minRemainder[currentR]; ok {
            candidate = val + prefixSum
        } else {
            candidate = -1 << 62
        }

        var currentDP int64
        if candidate > dpPrev {
            currentDP = candidate
        } else {
            currentDP = dpPrev
        }

        newVal := currentDP - prefixSum
        if val, ok := minRemainder[currentR]; ok {
            if newVal < val {
                minRemainder[currentR] = newVal
            }
        } else {
            minRemainder[currentR] = newVal
        }

        dpPrev = currentDP
    }

    return totalSum - dpPrev
}
